  4: "hsl(220, 60%, 55%)",   // blue
  5: "hsl(340, 60%, 55%)",   // pink
  6: "hsl(45, 80%, 60%)",    // gold
  7: "hsl(0, 0%, 15%)",      // black
  8: "hsl(0, 0%, 90%)",      // white
