export const ALL_PUZZLES: PixelPuzzle[] = [...easyPuzzles, ...mediumPuzzles, ...hardPuzzles];

export function getPuzzlesByDifficulty(difficulty: Difficulty): PixelPuzzle[] {
  return ALL_PUZZLES.filter((p) => p.difficulty === difficulty);
}

export function getPuzzleById(id: string): PixelPuzzle | undefined {
  return ALL_PUZZLES.find((p) => p.id === id);
}
